#include <vector>
#include <algorithm>

void adaptive_sort(std::vector<int>& arr) {
    const size_t n = arr.size();
    if (n < 2) return;

    bool ascending = true;
    bool descending = true;

    // Combined single-pass scan for sorted or reverse-sorted sequences
    for (size_t i = 1; i < n; ++i) {
        if (arr[i] < arr[i-1]) {
            ascending = false;
            // If it's no longer ascending AND it was already not descending,
            // it's neither sorted nor reverse-sorted. Break early.
            if (!descending) {
                std::sort(arr.begin(), arr.end());
                return;
            }
        } else if (arr[i] > arr[i-1]) {
            descending = false;
            // If it's no longer descending AND it was already not ascending,
            // it's neither sorted nor reverse-sorted. Break early.
            if (!ascending) {
                std::sort(arr.begin(), arr.end());
                return;
            }
        }
    }

    // If the array is descending (and not necessarily ascending), reverse it.
    // If it is ascending (or both, meaning all elements are equal), it's already sorted.
    if (descending) {
        std::reverse(arr.begin(), arr.end());
    }
}

